var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"가장 행복했던 시절의 소녀가 보인다.","JPN":"一番幸せだった頃の少女が見える。","ENG":"In front of me, I see a girl when she was the happiest.","TWN":"我看到了一個她最快樂的時光。"},"stage":{"bg":"WHITE","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_5"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀에겐 자신의 누이가 세상의 전부였고, 숭배하는 모든 것이었다.","JPN":"彼女には自分の姉が世界の全てであり、崇拝する全てであった。","ENG":"Her sister was her whole world and everything she worshipped.","TWN":"對她來說，姊姊就是世界上的一切，是她崇拜的一切。"},"stage":{"bg":"WHITE","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_6"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 나의 그릇된 믿음은… 그 아이의 하나뿐인 세계를 무너뜨렸다.","JPN":"そして我の誤った信仰は……その子どもにとって唯一の世界を壊してしまった。","ENG":"And my wrongful beliefs... destroyed that child's only world.","TWN":"而我扭曲的信仰……毀掉了她唯一的世界。"},"stage":{"bg":"WHITE","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_7"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀가 무너트린 세계들의 비명 어린 발자취를 좇으며, 나는 이 끝없는 고통 속을 헤맸다.","JPN":"彼女が崩した世界の悲鳴がこもった足跡を追いかけながら、我はこの果てない苦痛の中で彷徨っていた。","ENG":"I wandered through endless pain, chasing after the trails of the screams from the fallen worlds.","TWN":"我追隨著被她摧毀的世界中充滿慘叫的腳步，在這無盡的痛苦中徘徊。"},"stage":{"bg":"WHITE","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_8"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 속죄를 위한 고행이라 믿었다.","JPN":"それが罪を償うための苦行だと信じた。","ENG":"I believed that it was a penance for atonement.","TWN":"我以為可以透過這種苦行來贖罪。"},"stage":{"bg":"WHITE","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_9"},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 이제는 알고 있다.","JPN":"でも今ならわかる。","ENG":"But now I know.","TWN":"但是現在我知道了。"},"stage":{"bg":"MS_1202","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_10"},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"지난 과거의 참혹한 풍경을 되풀이하지 않기 위해선.","JPN":"過ぎ去りし過去の残酷な情景を繰り返さないためには。","ENG":"In order to avoid revisiting the harrowing landscape of the past.","TWN":"為了避免重蹈覆轍。"},"stage":{"bg":"MS_1202","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_11"},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"그늘 아래의 속죄가 아닌 광명 아래의 수호로, 그릇된 순환을 끊어내야 한다는 것을.","JPN":"陰のもとで罪を償うのではなく、光のもとで守護することにより偽った循環を断ち切らなければならないということを。","ENG":"I must sever the wrongful cycle and be the guardian of light, rather than the atoning sinner in the shadows.","TWN":"斬斷惡性循環不能靠陰影下的贖罪，而是要靠光明下的守護。"},"stage":{"bg":"MS_1202","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_12"},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"세계의 존속을 바라는 수많은 목소리가 나의 귓가를 울린다.","JPN":"世界の存続を願うあまたの声が我の耳に響く。","ENG":"The countless voices of this world that want to live ring within my ears.","TWN":"希望世界存續的無數聲音在我耳邊響起。"},"stage":{"bg":"MS_1202","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_13"},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"이번엔 그 누구도, 살아가는 자들의 희망을 짓밟게 두진 않으리라.","JPN":"今回は誰であっても、生きていく者たちの希望を踏みにじることはできぬ。","ENG":"This time, I will not let anyone trample the hope of the living.","TWN":"這一次我不會讓任何人踐踏生者的希望。"},"stage":{"bg":"MS_1202","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_HARMONY_CA_ARMOR_IN_TRAILER_14"},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사라졌어요.","JPN":"消えました。","ENG":"It's gone.","TWN":"不見了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그 커다란 괴물이, 흔적도 없이.","JPN":"あんな大きい化け物が、跡もなく。","ENG":"That huge monster just vanished without a trace.","TWN":"那大怪物竟然消失得無影無蹤。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Yeah.","TWN":"……是啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사람들의 믿음으로 강해지는 힘이 있다니. 저런 광경은 처음 봤어.","JPN":"人々の信じる気持ちで強くなる力があるとは。あんな光景は初めて見たよ。","ENG":"Power that grows stronger with people's faith. I've never seen anything like it before.","TWN":"依靠人們的信仰變強的力量，我從沒見過這種場景。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"저 모습이… 모르스 씨의 과거…","JPN":"あの姿が……モールスさんの過去……","ENG":"That's... Mors' past...","TWN":"那是……死神過去的樣子……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그럼 모르스 씨는 그림자에서 인간으로 다시 돌아온 건가요?","JPN":"ではモールスさんはシャドウからまた人間に戻れたのですか？","ENG":"Does that mean Mors turned back into a human?","TWN":"這麼說，死神已經從暗影恢復成人類了？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원이 그림자의 강한 집념을 받아들인 결과라네.","JPN":"クリファ次元がシャドウの強い執念を受け入れた結果なのだ。","ENG":"It's the result of the Qlipha Dimension accepting the Shadow's strong desire.","TWN":"逆卡巴拉次元接受了暗影的強大執念。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀가 인간이 아니기 때문에 벌어질 수 있는 일종의 침식현상이지.","JPN":"彼女が人間ではないから起こすことのできる一種の侵食現象なわけだ。","ENG":"It is a type of Counterside Effect that only occurred because she is not human.","TWN":"這是因為她不是人類才可能發生的侵蝕現象。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그렇다면… 모르스 씨의 저 모습은 일시적인 거군요.","JPN":"なら……モールスさんのあの姿は一時的なものなんですね。","ENG":"Then... Mors' appearance is only temporary.","TWN":"這麼說……死神變成那副姿態應該只是暫時的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Correct.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금의 그녀에겐 그것만으로 충분할 걸세.","JPN":"しかし、今の彼女にはそれだけでも十分だろう。","ENG":"But to her, it is enough.","TWN":"不過對她來說已經足夠了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"모르스 씨.","JPN":"モールスさん。","ENG":"Mors.","TWN":"死神。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"저 함선으로 들어가시려는 거죠?","JPN":"あの艦船の中へ行くのですね？","ENG":"You're going into that ship, right?","TWN":"你想上那艘艦船，對吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"타기리온의 시선이 이곳에 닿은 이상 언젠가 그녀가 현실을 침범하는 날이 오겠지.","JPN":"タギリオンの視線がここまで及んだ以上、いつかは彼女が現実を侵犯する日が来るであろう。","ENG":"Thagirion has her sights set on this place. It will only be a matter of time before she invades the Normalside.","TWN":"既然塔基里翁目睹了這個世界，她早晚會來侵蝕現世。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"나는 나의 힘이 닿는 대로 그녀의 강림을 유예할 것이다.","JPN":"我は、我の力が及ぶかぎり、彼女の降臨を猶予するのだ。","ENG":"I will delay her arrival with all my strength.","TWN":"我會盡我所能推遲她的降臨。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그렇다면 저도 같이 갈게요!","JPN":"だったら、私も一緒に行きます！","ENG":"Then, I'll go with you!","TWN":"如果是這樣，我和你一起去！"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"이곳을 수호하는 건 다른 세계의 빛바랜 망집이 아닌 그대들의 몫이다.","JPN":"ここを守護するのは他の世界の色褪せた執念ではなく、そなたたちの役割だ。","ENG":"The guardians of this place are you, not this tarnished delusion from another world.","TWN":"守護這裡是你們的職責，而不能靠其他世界褪色的妄執。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"그러니 너는 이 세계에 남아 타기리온의 강림을 예비하거라.","JPN":"だからそなたはこの世界に残り、タギリオンの降臨に備えよ。","ENG":"So remain here, and prepare for Thagirion's arrival.","TWN":"所以你應該留在這個世界，準備應對塔基里翁的降臨。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……わかりました。","ENG":"…Understood.","TWN":"……明白了。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"네가 저 너머에서 아직 돌아오지 못한 이를 걱정하고 있다는 걸 안다.","JPN":"そなたが向こうからまだ帰っていない者を心配しているのはわかっておる。","ENG":"I know you are worried about the one who has not yet returned from the beyond.","TWN":"我知道你在擔心從另一邊尚未歸來的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"마에스트로와 달리, 레아 슈나이더는 이 세계에 속해 있어야 할 존재일지니.","JPN":"マエストロとは違ってレア・シュナイダーはこの世界に属すべき存在。","ENG":"Unlike Maestra, Leah Schneider belongs to this world.","TWN":"與指揮家不同，蕾亞·修奈德是屬於這個世界的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"타기리온이 그녀를 함부로 해하지 못하도록, 내가 막을 것이다.","JPN":"タギリオンが彼女に害を及ぼさないよう、我が止めよう。","ENG":"I will stop Thagirion from harming her.","TWN":"我會阻止塔基里翁傷害她。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_ARMOR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"네!","JPN":"はいっ！","ENG":"Okay!","TWN":"是！"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"저도…  최선을 다하겠어요.","JPN":"私も……最善を尽くします。","ENG":"I'll... also do my best.","TWN":"我會.……盡全力。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하늘에서 느껴지던 불길한 시선이… 사라졌어.","JPN":"空から感じていた不吉な視線が……消えた。","ENG":"The ominous gaze from above... is gone.","TWN":"天空中那不祥的目光……消失了。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이걸로, 전부 끝난 걸까요?","JPN":"これで、全部終わったのですか？","ENG":"Is it all over now?","TWN":"都結束了嗎？"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한 번 열려버린 클리파 차원을 막아낼 방법은 없다네.","JPN":"一度開いてしまったクリファ次元を止めるすべはないのだ。","ENG":"There is no way to stop the Qlipha Dimension once it is open.","TWN":"逆卡巴拉次元一旦被打開就沒辦法關閉。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕 타기리온이 이곳에 다다르는 건, 시간 문제겠지.","JPN":"魔王タギリオンがここに辿りつくのは時間の問題だろうな。","ENG":"It's only a matter of time before the Demon Lord Thagirion reaches this world.","TWN":"魔王塔基里翁遲早會到來。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그림자의 희생으로 세상을 구한다라.","JPN":"シャドウの犠牲によって世界を救う、か。","ENG":"Saving the world by sacrificing a Shadow.","TWN":"用暗影的犧牲拯救世界。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비극적인 결말을 비틀어버린 참신한 반전이군요.","JPN":"悲劇的な結末をひねった斬新などんでん返しですね。","ENG":"What a novel solution to twist the plot of a tragic ending.","TWN":"這個結局很新穎，不同於普通的悲劇結尾。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…스완!","JPN":"……スワン！","ENG":"...Swan!","TWN":"……史旺！"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"안돼요, 선배님!","JPN":"ダメです、先輩！","ENG":"No, Mina!","TWN":"不要，前輩！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘?","JPN":"ノエル？","ENG":"Noelle?","TWN":"洛艾兒？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이미… 너무 많이 다치셨어요.","JPN":"これ以上は…怪我が酷すぎます。","ENG":"You're... already too injured.","TWN":"你已經……受了太多的傷。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 덤비지 않는다면, 저도 굳이 상대할 생각은 없습니다.","JPN":"あなたの方から攻撃しないのなら、私も攻撃する気はありません。","ENG":"If you don't attack me, then I've no intention of fighting you.","TWN":"如果你停手，我也不會主動出手。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 계약에 당신들의 목숨을 거두는 일은 포함되지 않으니까요.","JPN":"私の契約にあなたたちを殺すことは含まれておりませんので。","ENG":"Because my contract doesn't include ending your lives.","TWN":"我的合約裡不包括奪走你們的生命這一條款。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕을 불러들인다는 게 어떤 의미인지 알면서 그런 소릴 하다니. 위선적이군.","JPN":"魔王を呼び寄せると言うことがどういうことかわかっていながらそんなことを言うとは、偽善的だな。","ENG":"How hypocritical, fully knowing what summoning the Demon Lord means.","TWN":"你明知道召喚魔王表示什麼還說這種虛偽的話。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"의외였어요. 제 각본의 주역을, 당신이 역으로 이용할 줄은 몰랐거든요.","JPN":"以外でした。私の脚本の主役を、あなたが逆手に取るとは思いませんでした。","ENG":"I was surprised. I didn't think you would use my script's heroine against me.","TWN":"這是個意外，因為我沒想到你會反手利用我劇本裡的主角。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이용하진 않았네. 자네의 각본에 스포트라이트를 더했을 뿐이니까.","JPN":"利用したわけではない。君の脚本にスポットライトを加えただけだ。","ENG":"I didn't use her. All I did was add a spotlight to your script.","TWN":"我沒利用。我只是讓你的劇本更受矚目而已。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 방법은 자네가 방주의 봉인을 제거해야만 실행에 옮길 수 있는 계획이었지.","JPN":"しかし、この方法は君が箱舟の封印を解かなければ使えない計画だったからな。","ENG":"But this plan was only viable if you had removed the Ark's seal.","TWN":"但這個計畫只有你解除了方舟封印才能付諸實行。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결과적으론… 나의 패배로군.","JPN":"結果的には……私の負けだ。","ENG":"In the end... It's my defeat.","TWN":"到最後……我還是失敗了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"최악을 피하기 위해 당장의 희망을 과감히 포기하는 것.","JPN":"最悪を回避するために、目の前の希望を果敢に諦めること。","ENG":"Giving up immediate hope to avoid the worst.","TWN":"為了避免最壞的結果果斷放棄眼前的希望。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"나유빈 씨도 비슷한 선택을 했었죠.","JPN":"イチノセさんも似たような選択をしてましたよね。","ENG":"Na Yubin made a similar choice.","TWN":"羅瑜斌也做出過類似的選擇。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들은 닮아 있네요.","JPN":"あなたたちは似ています。","ENG":"You two seem to have a lot in common.","TWN":"你們兩個人很像。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식된 세계를 끌어들일 때, 자네는 돌려받고 싶은 게 있다고 말했지.","JPN":"侵食された世界を引き入れた時、君は返してもらいたいものがあると言ったな。","ENG":"When you were bringing the Corrupted world here, you said you wanted to get something back.","TWN":"召喚被侵蝕的世界時，你說你想要回一些東西。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"타기리온을 끌어들인 건… 클리포트게임이 목적인 건가?","JPN":"タギリオンを引き入れたのは……クリフォトゲームが目的か？","ENG":"Did you summon Thagirion... for the Qliphoth Game?","TWN":"你把塔基里翁帶進來……是為了逆卡巴拉遊戲？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"계약을 했거든요.","JPN":"契約をしたんです。","ENG":"I signed a contract.","TWN":"因為我約定好了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 세계를 바치는 대가로, 그녀의 소원은 내가 갖기로 말이죠.","JPN":"この世界を捧げる代わりに、彼女の願いを私がもらうと。","ENG":"In return for offering this world, I would get the rights to her wish.","TWN":"作為獻出這個世界的代價，我會得到她的願望。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아이러니하군.","JPN":"皮肉なものだな。","ENG":"How ironic.","TWN":"真諷刺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자기 세계를 멸망시킨 자에게 희망을 맡기다니 말이야.","JPN":"自分の世界を滅ぼした相手に、希望を託すとは。","ENG":"Leaving hope to the one who destroyed your own world.","TWN":"把希望寄託在毀滅自己世界的人身上。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이해 받길 원했다면 이런 일은 시작하지도 않았겠죠.","JPN":"理解して欲しいと思うなら、こんなことは最初からやりません。","ENG":"If I wanted to be understood, I would not have started this in the first place.","TWN":"如果是為了得到理解，我就不會這樣做了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원하는 것이 있으면 원수와도 손을 잡는다… 참 단순한 심리로군.","JPN":"望むものがあるなら、仇とも手を組む……まったく単純な思考だな。","ENG":"Getting in bed with the enemy to get what you want... Quite simple.","TWN":"為了目的甘願與仇人聯手……真是單純。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네가 노엘 양에게 보여준 광경은 그리 단순한 사연이 아닌 것 같던데.","JPN":"だが君がノエル君に見せた光景はそんな単純な話ではないと思うのだが。","ENG":"However, what you showed Noelle didn't seem like such a simple tale.","TWN":"但你給洛艾兒展現的場景似乎並沒有那麼單純。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임은 <color=#ffd34c>어떤 존재</color>에 의해 이뤄지는 것.","JPN":"クリフォトゲームは<color=#ffd34c>ある存在</color>によって行われるもの。","ENG":"The Qliphoth Game is created by a <color=#ffd34c>certain being</color>.","TWN":"逆卡巴拉遊戲依託於<color=#ffd34c>某種存在</color>。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 모든 것이 <color=#ffd34c>그 존재</color>가 만들어낸 규칙에 갇혀 있진 않아요.","JPN":"しかし、全てが<color=#ffd34c>その存在</color>が作ったルールに縛られているわけではありません。","ENG":"But not everything is bound by the rules <color=#ffd34c>this being</color> makes.","TWN":"但並非一切都受困於由<color=#ffd34c>那個存在</color>創造的規矩中。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 일전에 드렸던 경고를 부디 기억하고 계신다면 좋겠네요.","JPN":"私が以前差し上げた警告を、どうか覚えていて欲しいですね。","ENG":"I hope you still remember the warning I gave you last time.","TWN":"希望你還記得我不久前給你的警告。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"커튼콜은 여기까지.","JPN":"カーテンコールはここまで。","ENG":"This is where the curtain call ends.","TWN":"這齣戲就此謝幕。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임의 막이 열리는 날, 다시 뵙도록 하죠.","JPN":"クリフォトゲームの幕が上がるその日に、またお会いしましょう。","ENG":"We shall meet again when the Qliphoth Game begins.","TWN":"逆卡巴拉遊戲拉開序幕的那一天，我們再見吧。"},"stage":{"bg":"SKY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};